// // This module implements a 5-bit PIPO shift register with parallel input, clock, reset, and output. On the rising edge of the clock, if the reset is high, the register is cleared. If reset is low, the data present on the input is loaded into the register.
module pipo_shift_register (
    input wire clk,
    input wire reset,
    input wire [4:0] parallel_in,
    output reg [4:0] parallel_out
);

always @(posedge clk or posedge reset) begin
    if (reset) begin
        parallel_out <= 5'b00000;
    end else begin
        parallel_out <= parallel_in;
    end
end

endmodule
